package il.co.dcd.composermapper.index; import il.co.dcd.composermapper.model.DiscoveredFile; import il.co.dcd.composermapper.service.ProcessingReport; import il.co.dcd.composermapper.util.XmlParseException; import java.util.List;
public class IndexBuildService { private final IniMappingIndexer ini=new IniMappingIndexer(); private final JavaClassIndexer javaIdx=new JavaClassIndexer(); private final XmlDefinitionIndexer xml=new XmlDefinitionIndexer(); public Indexes build(List<DiscoveredFile> files){ return build(files,new ProcessingReport()); } public Indexes build(List<DiscoveredFile> files, ProcessingReport report){ Indexes x=Indexes.create(); for(var f:files) if(f.type()==DiscoveredFile.FileType.INI) ini.index(f.path(),x); for(var f:files) if(f.type()==DiscoveredFile.FileType.JAVA) javaIdx.index(f.path(),x); for(var f:files) if(f.type()==DiscoveredFile.FileType.XML) try{ xml.index(f.path(),x); }catch(XmlParseException e){ report.recordXmlFailure(f.path(),e); } xml.finalizeUnresolved(x); return x; } }
